mapper.select:
SELECT

FROM asset_transfer t0 left join property_bill propBill on t0.id = propBill.do_id
left join customer_info customerInfo on customerInfo.id = t0.custom_id
left join agency agency on agency.id = t0.estimate_id


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.flow_state = #{request.flowState}


    AND propBill.property_id = #{request.propertyId}


    AND t0.id = #{request.id}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.custom_id = #{request.customId}


    AND customerInfo.customer_name LIKE CONCAT('%',#{request.customName},'%')


    AND t0.estimate_id = #{request.estimateId}


    AND agency.agency_name LIKE CONCAT('%',#{request.estimateName},'%')


    AND t0.estimate_money = #{request.estimateMoney}


    AND t0.estimate_date = #{request.estimateDate}


    AND t0.estimate_date BETWEEN

      #{item}



    AND t0.deal_money = #{request.dealMoney}


    AND t0.deal_date = #{request.dealDate}


    AND t0.deal_date BETWEEN

      #{item}



    AND t0.taxation = #{request.taxation}


    AND t0.transfer_ownership_date = #{request.transferOwnershipDate}


    AND t0.contacts = #{request.contacts}


    AND t0.contacts_phone = #{request.contactsPhone}


    AND t0.programme = #{request.programme}


    AND t0.remark = #{request.remark}


    AND t0.is_deleted = #{request.isDeleted}


GROUP BY t0.id


    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
